.darma-loader-darma-custom-383 {color: var(--loader-color, #7c3aed);
  --loader-secondary-color: #c084fc;
  --loader-bg: #ffffff;
  width: 120px;
  height: 20px;
  background:linear-gradient(90deg, #0000 ,var(--loader-color, #7c3aed)) left -50px top 0/50px 20px no-repeat var(--loader-secondary-color, #c084fc);
  animation: darma-loader-darma-custom-383-l2 1s infinite linear;
}@keyframes darma-loader-darma-custom-383-l2 {100% {background-position: right -50px top 0}}

